    int solveRec(int n,vector<int>&nums,int curr,int prev){
        if(curr == n) return 0;

        //include
        int take=0;
        if(prev == -1 || nums[curr]>nums[prev]){
            take = 1 + solveRec(n,nums,curr+1,curr);
        }
        //exclude
        int notTake = 0 + solveRec(n,nums,curr+1,prev);
        return max(take,notTake);
